--
-- Table structure for table `tenant_contracts`
--

CREATE TABLE `tenant_contracts` (
  `id` int(11) NOT NULL,
  `tenant_detail_id` int(11) NOT NULL,
  `tenant_user_id` int(11) NOT NULL,
  `stall_id` int(11) DEFAULT NULL,
  `contract_status` enum('draft','final') DEFAULT 'draft',
  `contract_path` varchar(255) NOT NULL,
  `contract_html` longtext DEFAULT NULL,
  `lease_start_date` date DEFAULT NULL,
  `lease_end_date` date DEFAULT NULL,
  `version` int(11) DEFAULT 1,
  `generated_by` int(11) NOT NULL,
  `notes` text DEFAULT NULL,
  `send_email` tinyint(1) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

