INSERT INTO `tenant_contracts` (`id`, `tenant_detail_id`, `tenant_user_id`, `stall_id`, `contract_status`, `contract_path`, `contract_html`, `lease_start_date`, `lease_end_date`, `version`, `generated_by`, `notes`, `send_email`, `created_at`, `updated_at`) VALUES
(1, 72, 84, 31, 'draft', 'uploads/contracts/72/contract_20251201_073854_draft.html', '<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <title>Stall Rental Contract</title>\r\n    <style>\r\n        body {\r\n            font-family: \'Times New Roman\', serif;\r\n            margin: 0;\r\n            padding: 40px;\r\n            color: #1f2937;\r\n            background: #f9fafb;\r\n            font-size: 14px;\r\n            line-height: 1.6;\r\n        }\r\n        .contract-wrapper {\r\n            max-width: 900px;\r\n            margin: auto;\r\n            background: #ffffff;\r\n            border-radius: 16px;\r\n            box-shadow: 0 20px 40px rgba(15, 23, 42, 0.1);\r\n            overflow: hidden;\r\n            border: 1px solid #e5e7eb;\r\n        }\r\n        .contract-header {\r\n            background: linear-gradient(135deg, #0ea5e9 0%, #10b981 100%);\r\n            color: white;\r\n            padding: 40px;\r\n        }\r\n        .contract-header h1 {\r\n            margin: 0;\r\n            font-size: 32px;\r\n            letter-spacing: 1px;\r\n        }\r\n        .contract-meta {\r\n            margin-top: 16px;\r\n            font-size: 14px;\r\n            opacity: 0.85;\r\n        }\r\n        .contract-body {\r\n            padding: 40px;\r\n            line-height: 1.7;\r\n        }\r\n        h2.section-title {\r\n            font-size: 20px;\r\n            margin-top: 32px;\r\n            margin-bottom: 12px;\r\n            color: #0f172a;\r\n            text-transform: uppercase;\r\n            letter-spacing: 0.08em;\r\n        }\r\n        .info-grid {\r\n            display: grid;\r\n            grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\r\n            gap: 16px;\r\n            margin-top: 16px;\r\n        }\r\n        .info-card {\r\n            background: #f8fafc;\r\n            border: 1px solid #e2e8f0;\r\n            border-radius: 12px;\r\n            padding: 16px;\r\n        }\r\n        .info-card span.label {\r\n            display: block;\r\n            font-size: 12px;\r\n            text-transform: uppercase;\r\n            color: #64748b;\r\n            letter-spacing: 0.08em;\r\n        }\r\n        .info-card span.value {\r\n            display: block;\r\n            font-size: 16px;\r\n            font-weight: 600;\r\n            margin-top: 6px;\r\n            color: #0f172a;\r\n        }\r\n        ul.custom-list {\r\n            margin: 12px 0 0 20px;\r\n        }\r\n        ul.custom-list li {\r\n            margin-bottom: 8px;\r\n            color: #334155;\r\n        }\r\n        .signature-section {\r\n            margin-top: 48px;\r\n            display: grid;\r\n            grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));\r\n            gap: 40px;\r\n            align-items: end;\r\n        }\r\n        .signature-block {\r\n            text-align: center;\r\n        }\r\n        .signature-line {\r\n            margin-top: 16px;\r\n            border-top: 1px solid #94a3b8;\r\n            padding-top: 8px;\r\n            font-size: 14px;\r\n            color: #475569;\r\n        }\r\n        .signature-img {\r\n            max-width: 260px;\r\n            max-height: 120px;\r\n            object-fit: contain;\r\n        }\r\n        .footer-note {\r\n            margin-top: 40px;\r\n            font-size: 12px;\r\n            color: #94a3b8;\r\n            text-align: center;\r\n        }\r\n        .highlight-box {\r\n            border-left: 4px solid #10b981;\r\n            background: #ecfdf5;\r\n            padding: 16px;\r\n            border-radius: 12px;\r\n            margin-top: 16px;\r\n        }\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class=\"contract-wrapper\">\r\n        <div class=\"contract-header\">\r\n            <h1>Stall Rental Agreement</h1>\r\n            <div class=\"contract-meta\">\r\n                <div>Contract No.: <strong>XM-692D37FE-72</strong></div>\r\n                <div>Generated on: December 01, 2025 7:38 AM</div>\r\n            </div>\r\n        </div>\r\n        <div class=\"contract-body\">\r\n            <h2 class=\"section-title\">Parties Involved</h2>\r\n            <p>\r\n                This Stall Rental Contract (the “Agreement”) is made between <strong>Xentro Mall Management</strong>,\r\n                located at XentroMall, Main Street, City (hereinafter referred to as the “Lessor” or “Mall”), and\r\n                <strong>Stephanie Reyes</strong> of <strong>JG Tech Supplies, Inc.</strong>,\r\n                with contact email sarah@gmail.com (hereinafter referred to as the “Lessee” or “Tenant”).\r\n            </p>\r\n\r\n            <h2 class=\"section-title\">Stall Details</h2>\r\n            <div class=\"info-grid\">\r\n                <div class=\"info-card\">\r\n                    <span class=\"label\">Stall Number</span>\r\n                    <span class=\"value\">EX -001</span>\r\n                </div>\r\n                <div class=\"info-card\">\r\n                    <span class=\"label\">Location</span>\r\n                    <span class=\"value\">Exhibit stall for weekly pop-up displays</span>\r\n                </div>\r\n                <div class=\"info-card\">\r\n                    <span class=\"label\">Floor Area</span>\r\n                    <span class=\"value\">5m x 6m</span>\r\n                </div>\r\n                <div class=\"info-card\">\r\n                    <span class=\"label\">Monthly Rental Fee</span>\r\n                    <span class=\"value\">₱6,500.00</span>\r\n                </div>\r\n            </div>\r\n\r\n            <h2 class=\"section-title\">Term of Lease</h2>\r\n            <div class=\"highlight-box\">\r\n                <strong>Effectivity:</strong>\r\n                November 10, 2025 up to November 10, 2028                (36 month(s)).\r\n            </div>\r\n\r\n            <h2 class=\"section-title\">Payment Terms</h2>\r\n            <ul class=\"custom-list\">\r\n                <li>Monthly rental fee: <strong>₱6,500.00</strong></li>\r\n                <li>Payment due every <strong>5th of the month</strong> of the month.</li>\r\n                <li>Accepted mode(s) of payment: <strong>Bank Deposit / GCash</strong></li>\r\n                <li>Late payment penalty: <strong>5% per day of delay</strong></li>\r\n                <li>Advance payment: <strong>1 month advance</strong></li>\r\n                <li>Security deposit: <strong>2 months security deposit</strong> (refundable subject to contract compliance)</li>\r\n            </ul>\r\n\r\n            <h2 class=\"section-title\">Rules and Regulations</h2>\r\n            <p>The Tenant agrees to abide by the mall’s policies and regulations, which include but are not limited to:</p>\r\n            <ul class=\"custom-list\">\r\n                                    <li>Bawal magbago ng layout ng stall nang walang written approval mula sa mall management.</li>\r\n                                    <li>Panatilihing malinis at maayos ang stall sa lahat ng oras.</li>\r\n                                    <li>Sundin ang mall operating hours at security protocols.</li>\r\n                                    <li>Bawal magbenta ng ipinagbabawal o mapanganib na produkto.</li>\r\n                            </ul>\r\n\r\n            <h2 class=\"section-title\">Maintenance & Utilities</h2>\r\n            <p>The tenant shall shoulder electricity and water consumption.</p>\r\n\r\n            <h2 class=\"section-title\">Termination</h2>\r\n            <p>Either party may terminate the contract by giving a 30-day written notice.</p>\r\n\r\n            <h2 class=\"section-title\">Liability</h2>\r\n            <p>The tenant shall be liable for any damages to mall property beyond normal wear and tear.</p>\r\n\r\n            <div class=\"signature-section\">\r\n                <div class=\"signature-block\">\r\n                    <p class=\"label\">For the Mall (Lessor)</p>\r\n                                            <div class=\"signature-img\" style=\"border: 1px dashed #94a3b8; padding: 30px 0; color: #94a3b8;\">\r\n                            Signature Pending\r\n                        </div>\r\n                                        <div class=\"signature-line\">\r\n                        <strong>Mall Administrator</strong><br>\r\n                        Mall Administrator                    </div>\r\n                </div>\r\n                <div class=\"signature-block\">\r\n                    <p class=\"label\">For the Tenant (Lessee)</p>\r\n                    <div class=\"signature-img\" style=\"border: 1px dashed #94a3b8; padding: 30px 0; color: #94a3b8;\">\r\n                        Tenant Signature\r\n                    </div>\r\n                    <div class=\"signature-line\">\r\n                        <strong>Stephanie Reyes</strong><br>\r\n                        JG Tech Supplies, Inc.                    </div>\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\"footer-note\">\r\n                This document was generated electronically by XentroMall Management System. Printed copies are considered uncontrolled unless signed and dated.\r\n            </div>\r\n        </div>\r\n    </div>\r\n</body>\r\n</html>\r\n\r\n', '2025-11-10', '2028-11-10', 1, 7, '', 1, '2025-12-01 06:38:54', '2025-12-01 06:38:54'),
